function fb(a, b) { if (a) { return a; } return b; }
var content = fb($.input.originalContent, '');
var title = fb($.input.contentTitle, '');
var platforms = fb($.input.targetPlatforms, 'twitter,linkedin,instagram,blog,email');
var voice = fb($.input.brandVoice, 'professional yet approachable');

var prompt = 'You are a social media strategist and content repurposing expert. Take the following content and adapt it for multiple platforms, optimizing for each platform\'s unique format and audience.\n\n';
if (title) prompt += 'CONTENT TITLE: ' + title + '\n';
prompt += 'BRAND VOICE: ' + voice + '\n';
prompt += 'TARGET PLATFORMS: ' + platforms + '\n\n';
prompt += 'ORIGINAL CONTENT:\n' + content.slice(0, 5000) + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Adapt tone and length for each platform\n';
prompt += '- Twitter: Thread format, punchy hooks, use line breaks\n';
prompt += '- LinkedIn: Professional, story-driven, with a CTA\n';
prompt += '- Instagram: Visual-friendly caption with emojis and hashtags\n';
prompt += '- Blog: SEO excerpt with compelling hook\n';
prompt += '- Email: Newsletter-style with subject line and preview text\n';
prompt += '- Include relevant hashtags per platform\n';
prompt += '- Maintain core message across all formats\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "coreTakeaway": "the central message in one sentence",\n';
prompt += '  "platforms": {\n';
prompt += '    "twitter": { "thread": ["tweet 1", "tweet 2", "tweet 3"], "hashtags": ["#tag"], "hookScore": "1-10" },\n';
prompt += '    "linkedin": { "post": "full linkedin post", "hashtags": ["#tag"], "cta": "call to action" },\n';
prompt += '    "instagram": { "caption": "instagram caption", "hashtags": ["#tag"], "suggestedVisual": "image description" },\n';
prompt += '    "blog": { "excerpt": "blog excerpt", "metaDescription": "SEO meta", "suggestedTitle": "blog title" },\n';
prompt += '    "email": { "subjectLine": "email subject", "previewText": "preview text", "body": "email body" }\n';
prompt += '  },\n';
prompt += '  "publishingOrder": ["recommended order of posting"],\n';
prompt += '  "bestTimeToPost": { "twitter": "time", "linkedin": "time", "instagram": "time" },\n';
prompt += '  "contentCalendarNote": "suggestion for follow-up content"\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiRepurpose.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { coreTakeaway: raw, platforms: {}, publishingOrder: [] }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;
var title = fb($.input.contentTitle, 'Content');

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':mega: Content Repurposed: ' + title, emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Core Takeaway:* ' + (fb(ai.coreTakeaway, '')) } });
blocks.push({ type: 'divider' });

var platforms = fb(ai.platforms, {});

if (platforms.twitter) {
  var tw = platforms.twitter;
  var threadText = '*:bird: Twitter Thread* (Hook: ' + (fb(tw.hookScore, '?')) + '/10)\n';
  var thread = fb(tw.thread, []);
  thread.forEach(function(tweet, i) { threadText += (i + 1) + '. ' + tweet + '\n'; });
  var twTags = (fb(tw.hashtags, [])).join(' ');
  if (twTags) threadText += '\n' + twTags;
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: threadText } });
  blocks.push({ type: 'divider' });
}

if (platforms.linkedin) {
  var li = platforms.linkedin;
  var liText = '*:briefcase: LinkedIn Post*\n';
  liText += (fb(li.post, '')).slice(0, 600);
  if (li.cta) liText += '\n\n*CTA:* ' + li.cta;
  var liTags = (fb(li.hashtags, [])).join(' ');
  if (liTags) liText += '\n' + liTags;
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: liText } });
  blocks.push({ type: 'divider' });
}

if (platforms.instagram) {
  var ig = platforms.instagram;
  var igText = '*:camera: Instagram Caption*\n';
  igText += (fb(ig.caption, '')).slice(0, 400);
  var igTags = (fb(ig.hashtags, [])).join(' ');
  if (igTags) igText += '\n' + igTags;
  if (ig.suggestedVisual) igText += '\n_Visual idea:_ ' + ig.suggestedVisual;
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: igText } });
  blocks.push({ type: 'divider' });
}

if (platforms.blog) {
  var blog = platforms.blog;
  var blogText = '*:newspaper: Blog Excerpt*\n';
  if (blog.suggestedTitle) blogText += '*Title:* ' + blog.suggestedTitle + '\n';
  blogText += (fb(blog.excerpt, '')).slice(0, 400);
  if (blog.metaDescription) blogText += '\n_Meta:_ ' + blog.metaDescription;
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: blogText } });
  blocks.push({ type: 'divider' });
}

if (platforms.email) {
  var em = platforms.email;
  var emText = '*:envelope: Email Newsletter*\n';
  emText += '*Subject:* ' + (fb(em.subjectLine, '')) + '\n';
  emText += '*Preview:* ' + (fb(em.previewText, '')) + '\n';
  emText += (fb(em.body, '')).slice(0, 400);
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: emText } });
  blocks.push({ type: 'divider' });
}

var order = fb(ai.publishingOrder, []);
if (order.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':clock1: *Posting order:* ' + order.join(' -> ') }] });
}

if (ai.contentCalendarNote) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':calendar: ' + ai.contentCalendarNote }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI + One CLI' }] });

var fallback = 'Content Repurposed: ' + title + ' for ' + Object.keys(platforms).length + ' platforms';
return { blocks: blocks, fallback: fallback };
